R Setup for Examples
Run this setup code before the example below. It installs any missing packages and helps R find the lecture data files whether you run the code from the course project folder, the Lectures folder, or the downloaded Lectures/code folder.


Code
load_packages &lt;- function(pkgs) {
  missing &lt;- pkgs[!vapply(pkgs, requireNamespace, logical(1), quietly = TRUE)]
  if (length(missing) &gt; 0) {
    install.packages(missing, repos = "https://cloud.r-project.org")
  }
  invisible(lapply(pkgs, library, character.only = TRUE))
}

lecture_data &lt;- function(filename) {
  args &lt;- commandArgs(trailingOnly = FALSE)
  file_arg &lt;- grep("^--file=", args, value = TRUE)
  script_dir &lt;- if (length(file_arg) &gt; 0) {
    dirname(normalizePath(sub("^--file=", "", file_arg)))
  } else {
    getwd()
  }

  candidates &lt;- c(
    filename,
    file.path("Lectures", filename),
    file.path("..", filename),
    file.path(script_dir, "..", filename),
    file.path(script_dir, "..", "..", "Lectures", filename)
  )

  hit &lt;- candidates[file.exists(candidates)]
  if (length(hit) == 0) {
    stop("Could not find ", filename, ". Run from the project, Lectures, or Lectures/code folder.")
  }
  normalizePath(hit[1], winslash = "/")
}

